<script>
import { rentData, commuteData } from '@/data/realData';

export default {
  name: 'InteractionPage',
  data() {
    return {
      form: {
        income: 8000,
        workStation: 'tiyuxilu',
        liveStation: 'tonghe',
        hourlyWage: 50
      },
      calculating: false,
      showResult: false,
      result: {}
    }
  },
  methods: {
    calculate() {
      this.calculating = true;
      
      setTimeout(() => {
        const liveData = rentData[this.form.liveStation];
        // 用双层索引：按工作地点 → 居住地点
        const commuteInfo = commuteData[this.form.workStation][this.form.liveStation];
        // 以"同一工作地点、住体育西路"为节省基准
        const baseCommuteInfo = commuteData[this.form.workStation].tiyuxilu;

        // 计算月度成本
        const rent = liveData.avgRent;
        const transport = commuteInfo.monthlyPass;
        const commuteHours = Math.round(commuteInfo.timeCostPerYear / 12);
        const timeCost = Math.round(commuteHours * this.form.hourlyWage);
        const totalMonthlyCost = rent + transport + timeCost;
        
        // 计算年度节省（相比：同工作地 × 住体育西路）
        const baseRent = rentData.tiyuxilu.avgRent;
        const rentSavings = (baseRent - rent) * 12;
        // 交通差额：正数=增加，负数=节省
        const transportIncrease = (transport - baseCommuteInfo.monthlyPass) * 12;
        // 时间差额：正数=增加，负数=节省
        const timeOpportunityCost = Math.round(
          (commuteInfo.timeCostPerYear - baseCommuteInfo.timeCostPerYear) * this.form.hourlyWage
        );
        const annualSavings = Math.round(rentSavings - transportIncrease - timeOpportunityCost);
        
        // 租金收入比
        const rentRatio = ((rent / this.form.income) * 100).toFixed(1);
        
        // 生活质量评分
        const rentBurdenScore = Math.max(0, 100 - (rent / this.form.income) * 200);
        const commuteScore = Math.max(0, 100 - commuteInfo.time * 2);
        const savingScore = Math.min(100, ((this.form.income - rent - transport) / this.form.income) * 150);
        const overallScore = Math.round((rentBurdenScore + commuteScore + savingScore) / 3);
        
        // 个性化建议
        let recommendation = '';
        if (rentRatio < 30) {
          recommendation = `你的租金收入比为${rentRatio}%，处于舒适区间。当前居住选择很合理，既能保证生活质量，又有较强的储蓄能力。`;
        } else if (rentRatio < 40) {
          recommendation = `你的租金收入比为${rentRatio}%，处于可接受范围。如果想增加储蓄，可以考虑再往外搬1-2站。`;
        } else {
          recommendation = `你的租金收入比为${rentRatio}%，租金压力较大。强烈建议考虑更远的站点，如龙归或大石，可以显著降低生活压力。`;
        }
        
        this.result = {
          rent,
          transport,
          commuteHours,
          timeCost,
          totalMonthlyCost,
          rentSavings,
          transportIncrease,
          timeOpportunityCost,
          annualSavings,
          rentRatio: parseFloat(rentRatio),
          rentBurdenScore: Math.round(rentBurdenScore),
          commuteScore: Math.round(commuteScore),
          savingScore: Math.round(savingScore),
          overallScore,
          recommendation
        };
        
        this.calculating = false;
        this.showResult = true;
        
        // 滚动到结果区域
        this.$nextTick(() => {
          const resultSection = document.querySelector('.result-section');
          if (resultSection) {
            resultSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
          }
        });
      }, 800);
    },
    
    getRatioClass(ratio) {
      if (ratio < 30) return 'safe';
      if (ratio < 40) return 'warning';
      return 'danger';
    },
    
    getRatioEvaluation(ratio) {
      if (ratio < 30) return '舒适';
      if (ratio < 40) return '合理';
      if (ratio < 50) return '偏高';
      return '压力大';
    },
    
    getRatioDescription(ratio) {
      if (ratio < 30) return '租金负担轻，生活质量高，储蓄能力强';
      if (ratio < 40) return '租金负担适中，生活较为舒适';
      if (ratio < 50) return '租金负担偏重，建议考虑更远站点';
      return '租金负担过重，严重影响生活质量';
    },
    
    getScoreColor(score) {
      if (score >= 70) return '#67C23A';
      if (score >= 50) return '#E6A23C';
      return '#F56C6C';
    },
    
    goNext() {
      this.$parent.nextPage();
    }
  }
}
</script>

